module RefModule(
    Q  ,
    CLK,
    D  ,
    SCD,
    SCE
);output Q  ;
    input  CLK;
    input  D  ;
    input  SCD;
    input  SCE;


reg unused_q_reg;
wire mux_out;
assign mux_out = (SCE == 1'b1)? SCD : D;

always @ ( posedge CLK)
       begin
	     unused_q_reg <= mux_out;
       end

assign Q = unused_q_reg;

endmodule
